import shutil

def read_driver(context):
    metadata = context.get('driver', {})
    # The task specifies the C: drive, but we inspect metadata to see if a specific path is provided
    target_path = metadata.get('path', 'C:\\')
    
    try:
        usage = shutil.disk_usage(target_path)
        # Convert bytes to Gigabytes (1024^3)
        free_gb = usage.free / (1024**3)
        return {
            "drive": target_path,
            "free_space_gb": round(free_gb, 2),
            "status": "success"
        }
    except Exception as e:
        return {
            "drive": target_path,
            "error": str(e),
            "status": "failed"
        }

def read_driver(context):
    import os
    import shutil
    import platform

    # Get CPU load (using os.getloadavg if available, else fallback)
    try:
        cpu_load = os.getloadavg()[0]
    except (AttributeError, OSError):
        cpu_load = "unavailable"

    disk_info = {}
    # Checking common mount points for Windows and Linux
    paths_to_check = ["/", "C:\\"] if platform.system() == "Windows" else ["/"]

    for path in paths_to_check:
        if os.path.exists(path):
            try:
                usage = shutil.disk_usage(path)
                disk_info[path] = {
                    "total_gb": usage.total / (1024**3),
                    "free_gb": usage.free / (1024**3),
                    "used_gb": usage.used / (1024**3)
                }
            except Exception as e:
                disk_info[path] = f"Error: {str(e)}"

    return {
        "platform": platform.system(),
        "cpu_load_1min": cpu_load,
        "disk_usage": disk_info
    }

import subprocess
import platform
import re
import datetime

def read_driver(context):
    """
    Reads the network connectivity status by pinging key hosts.
    Supports custom host probes via context['driver']['extra_probes'].
    """
    sys_platform = platform.system().lower()
    ping_flag = '-n' if sys_platform == 'windows' else '-c'

    def ping_host(host, flag):
        try:
            # Ping 1 packet with a timeout to be responsive
            cmd = ['ping', flag, '1', host]
            output = subprocess.check_output(cmd, stderr=subprocess.STDOUT, universal_newlines=True, timeout=3)

            # Regex for latency: accommodates 'time=20ms', 'time<1ms', etc.
            match = re.search(r'time[=< ]([\d.]+)', output)
            latency = float(match.group(1)) if match else None

            return {'status': 'connected', 'latency_ms': latency}
        except Exception:
            return {'status': 'disconnected', 'latency_ms': None}

    # Default targets: Google DNS (Internet) and a common local gateway IP
    targets = ['8.8.8.8', '192.168.1.1']

    # Add extra probes from driver configuration
    try:
        driver_config = context.get('driver', {})
        extra_probes = driver_config.get('extra_probes', [])
        if isinstance(extra_probes, list):
            for probe in extra_probes:
                if probe not in targets:
                    targets.append(probe)
    except Exception:
        pass

    # Execute probes and build report
    connectivity_report = {}
    for host in targets:
        connectivity_report[host] = ping_host(host, ping_flag)

    return {
        'timestamp': datetime.datetime.now().isoformat(),
        'connectivity_report': connectivity_report
    }
